from kafka import admin
import sys

if __name__ == '__main__':
    if len(sys.argv) < 4:
        print("Usage: python kafka_admin.py <topic_name> <partitions> <replication_factor>")
        exit()

    topic_name = sys.argv[1]
    partitions = int(sys.argv[2])
    replication_factor = int(sys.argv[3])

    admin_client = admin.AdminClient()

    try:
        # Create the topic
        admin_client.create_topic(
            topic_name,
            partitions=partitions,
            replication_factor=replication_factor
        )

        # Configure topic settings
        admin_client.configure_topic_settings(
            topic_name,
            num_partitions=partitions,
            replication_factor=replication_factor
        )

    except Exception as e:
        print("Error occurred while creating or configuring the topic")
        print(e)